<body>
<form method="POST">
    {{ form.hidden_tag() }}
    {{ form.username.label }} {{ form.username() }}
    {{ form.password.label }} {{ form.password() }}
    {{ form.submit() }}
</form>
</body>
</html>'''

PROTECTED_TEMPLATE = '''<!DOCTYPE html>
<html>
<head><title>Protected</title></head>
